import React, { useEffect, useRef } from "react";
import { init } from "ityped";

export default function Intro() {
  const textRef = useRef();

  useEffect(() => {
    init(textRef.current, {
      backDelay: 1500,
      backSpeed: 60,
      showCursor: true,
      strings: ["Full Stack Developer"]
    });
  }, []);

  return (
    <div
      style={{
        backgroundColor: "white",
        display: "flex",
        flexDirection: "row",
        padding: "50px 20px",
        "@media screen and (max-width: 768px)": {
          flexDirection: "column",
          alignItems: "center"
        }
      }}
      id="intro"
    >
      <div
        style={{
          flex: "0.5",
          overflow: "hidden",
          display: "flex",
          justifyContent: "center",
          alignItems: "center"
        }}
      >
        <div
          style={{
            width: "300px",
            height: "300px",
            borderRadius: "50%",
            backgroundColor: "#f0f0f0",
            display: "flex",
            justifyContent: "center",
            alignItems: "center"
          }}
        >
          <img
            src="assets/soumya.jpg" // Replace with your own image
            alt="Soumya Ranjan Nayak"
            style={{
              width: "100%",
              height: "100%",
              borderRadius: "50%",
              objectFit: "cover"
            }}
          />
        </div>
      </div>

      <div
        style={{
          flex: "0.5",
          display: "flex",
          flexDirection: "column",
          justifyContent: "center",
          paddingLeft: "20px",
          "@media screen and (max-width: 768px)": {
            paddingLeft: "0",
            alignItems: "center"
          }
        }}
      >
        <h2 style={{ fontSize: "35px", marginBottom: "10px" }}>
          Hi, I'm Soumya Ranjan Nayak
        </h2>
        <h1 style={{ fontSize: "60px", margin: "10px 0" }}>
          I am a <span ref={textRef} style={{ fontSize: "inherit", color: "crimson" }}></span>
        </h1>
        <p style={{ fontSize: "20px", lineHeight: "1.6" }}>
          As a driven and adaptable professional, I thrive in challenging environments and am always eager to embrace opportunities for growth. My passion for continuous learning enables me to quickly master new skills and technologies, empowering me to deliver innovative and efficient solutions. I approach each project with a positive mindset and an unwavering commitment to excellence, aiming not only to meet but exceed expectations.
        </p>
        <p style={{ fontSize: "20px", lineHeight: "1.6" }}>
          With a versatile skill set and a strong foundation in problem-solving, I excel in dynamic environments, contributing effectively to team efforts and driving collective success. I am always seeking ways to make a meaningful impact, pushing boundaries and embracing new challenges along the way.
        </p>
      </div>
    </div>
  );
}
